21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	};
29	
30	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
31	
32	const sumItemBasePremiums = (items: Item[]): number =>
33	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
34	
35	const quotePremium = (items: Item[]): number => {
36	  const itemsBase = sumItemBasePremiums(items);
37	  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
38	  return Math.ceil(itemsBase + firstInsuranceSurcharge + PROCESSING_FEE);
39	};
40	
41	export const runScenario = (scenario: Scenario): ScenarioResult => {
42	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
43	  return { results };
44	};
