const quoteStep = (step: QuoteStep): QuoteResult => {
  const itemsBase = sumItemBasePremiums(step.items);
  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
  const premium = Math.ceil(itemsBase + firstInsuranceSurcharge + PROCESSING_FEE);
  return { premium };
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(quoteStep),
});
